// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract LikeRegistry {
    struct Like {
        bytes32 fromHash;
        bytes32 toHash;
        bytes32 proofHash;
        uint256 timestamp;
    }

    mapping(bytes32 => mapping(bytes32 => bool)) public likes;
    Like[] public allLikes;

    uint256 public likeFee = 0.001 ether;

    event LikeSubmitted(
        bytes32 indexed fromHash,
        bytes32 indexed toHash,
        bytes32 proofHash,
        uint256 timestamp
    );

    event MatchCreated(
        bytes32 indexed user1,
        bytes32 indexed user2,
        uint256 timestamp
    );

    modifier payLikeFee() {
        require(msg.value >= likeFee, "Insufficient fee");
        _;
    }

    function submitLike(
        bytes32 fromHash,
        bytes32 toHash,
        bytes32 proofHash
    ) external payable payLikeFee {
        require(!likes[fromHash][toHash], "Already liked");
        require(fromHash != toHash, "Cannot like yourself");

        likes[fromHash][toHash] = true;
        allLikes.push(Like(fromHash, toHash, proofHash, block.timestamp));

        emit LikeSubmitted(fromHash, toHash, proofHash, block.timestamp);

        if (likes[toHash][fromHash]) {
            emit MatchCreated(fromHash, toHash, block.timestamp);
        }
    }

    function hasLiked(bytes32 from, bytes32 to) external view returns (bool) {
        return likes[from][to];
    }

    function isMatch(bytes32 user1, bytes32 user2) external view returns (bool) {
        return likes[user1][user2] && likes[user2][user1];
    }

    function getLikesCount() external view returns (uint256) {
        return allLikes.length;
    }

    function getLike(uint256 index) external view returns (Like memory) {
        require(index < allLikes.length, "Index out of bounds");
        return allLikes[index];
    }

    function setLikeFee(uint256 _fee) external {
        likeFee = _fee;
    }

    receive() external payable {}
}

