// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract MatchRegistry {
    struct Match {
        bytes32 user1;
        bytes32 user2;
        uint256 timestamp;
        bool active;
    }

    Match[] public matches;
    mapping(bytes32 => bytes32[]) public userMatches;
    mapping(bytes32 => mapping(bytes32 => bool)) public isMatched;

    event MatchRegistered(
        uint256 indexed matchId,
        bytes32 indexed user1,
        bytes32 indexed user2,
        uint256 timestamp
    );

    event MatchDeactivated(uint256 indexed matchId);

    function registerMatch(bytes32 user1, bytes32 user2) external {
        require(!isMatched[user1][user2], "Already matched");
        require(user1 != user2, "Cannot match with yourself");

        bytes32 first = user1 < user2 ? user1 : user2;
        bytes32 second = user1 < user2 ? user2 : user1;

        uint256 matchId = matches.length;
        matches.push(Match(first, second, block.timestamp, true));

        userMatches[first].push(second);
        userMatches[second].push(first);
        isMatched[first][second] = true;
        isMatched[second][first] = true;

        emit MatchRegistered(matchId, first, second, block.timestamp);
    }

    function getMatch(uint256 matchId) external view returns (Match memory) {
        require(matchId < matches.length, "Invalid match ID");
        return matches[matchId];
    }

    function getUserMatches(bytes32 userHash) external view returns (bytes32[] memory) {
        return userMatches[userHash];
    }

    function getMatchesCount() external view returns (uint256) {
        return matches.length;
    }

    function deactivateMatch(uint256 matchId) external {
        require(matchId < matches.length, "Invalid match ID");
        matches[matchId].active = false;
        emit MatchDeactivated(matchId);
    }
}

