// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PaymentManager {
    uint256 public swipeFee = 0.001 ether;
    uint256 public messageFee = 0.0005 ether;
    uint256 public premiumUnlockFee = 0.01 ether;

    mapping(address => bool) public premiumUsers;
    mapping(address => uint256) public messageCredits;

    event SwipePayment(address indexed user, uint256 amount, uint256 timestamp);
    event MessagePayment(address indexed user, uint256 amount, uint256 credits, uint256 timestamp);
    event PremiumUnlocked(address indexed user, uint256 timestamp);
    event MessageProofStored(bytes32 indexed matchHash, bytes32 messageHash, uint256 timestamp);

    function payForSwipe() external payable {
        require(msg.value >= swipeFee, "Insufficient swipe fee");
        emit SwipePayment(msg.sender, msg.value, block.timestamp);
    }

    function payForMessages(uint256 count) external payable {
        require(count > 0, "Must buy at least 1 message");
        require(msg.value >= messageFee * count, "Insufficient message fee");
        messageCredits[msg.sender] += count;
        emit MessagePayment(msg.sender, msg.value, count, block.timestamp);
    }

    function unlockPremium() external payable {
        require(msg.value >= premiumUnlockFee, "Insufficient premium fee");
        require(!premiumUsers[msg.sender], "Already premium");
        premiumUsers[msg.sender] = true;
        emit PremiumUnlocked(msg.sender, block.timestamp);
    }

    function storeMessageProof(bytes32 matchHash, bytes32 messageHash) external {
        require(messageCredits[msg.sender] > 0, "No message credits");
        messageCredits[msg.sender]--;
        emit MessageProofStored(matchHash, messageHash, block.timestamp);
    }

    function isPremium(address user) external view returns (bool) {
        return premiumUsers[user];
    }

    function getMessageCredits(address user) external view returns (uint256) {
        return messageCredits[user];
    }

    function setFees(uint256 _swipe, uint256 _message, uint256 _premium) external {
        swipeFee = _swipe;
        messageFee = _message;
        premiumUnlockFee = _premium;
    }

    receive() external payable {}
}

